var mqtt = require('mqtt');
var websocket = require('websocket-stream');
var HttpsProxyAgent = require('https-proxy-agent');

function listenMqtt(defaultFuncs, api, ctx, globalCallback) {
    var chatOn = ctx.globalOptions.online;
    var foreground = false;
    var sessionID = Math.floor(Math.random() * 9007199254740991) + 1;
    var username = {
        u: ctx.userID,
        s: sessionID,
        chat_on: chatOn,
        fg: foreground,
        d: utils.getGUID(),
        ct: "websocket",
        aid: "219994525426954",
        mqtt_sid: "",
        cp: 3,
        ecp: 10,
        st: [],
        pm: [],
        dc: "",
        no_auto_fg: true,
        gas: null,
        pack: []
    };
    var cookies = ctx.jar.getCookies("https://www.facebook.com").join("; ");
    var host;
    if (ctx.mqttEndpoint) host = `${ctx.mqttEndpoint}&sid=${sessionID}`;
    else if (ctx.region) host = `wss://edge-chat.facebook.com/chat?region=${ctx.region.toLocaleLowerCase()}&sid=${sessionID}`;
    else host = `wss://edge-chat.facebook.com/chat?sid=${sessionID}`;
    var options = {
        clientId: "mqttwsclient",
        protocolId: 'MQIsdp',
        protocolVersion: 3,
        username: JSON.stringify(username),
        clean: true,
        wsOptions: {
            headers: {
                'Cookie': cookies,
                'Origin': 'https://www.facebook.com',
                'User-Agent': ctx.globalOptions.userAgent,
                'Referer': 'https://www.facebook.com/',
                'Host': new URL(host).hostname
            },
            origin: 'https://www.facebook.com',
            protocolVersion: 13
        },
        keepalive: 10,
        reschedulePings: false
    };
    if (typeof ctx.globalOptions.proxy != "undefined") {
        var agent = new HttpsProxyAgent(ctx.globalOptions.proxy);
        options.wsOptions.agent = agent;
    }
    ctx.mqttClient = new mqtt.Client(_ => websocket(host, options.wsOptions), options);
    var mqttClient = ctx.mqttClient;
    mqttClient.on('error', function(err) {
        log.error("listenMqtt", "Connection refused: Server unavailable. Exiting...");
        mqttClient.end();
        process.exit();
        if (ctx.globalOptions.autoReconnect) getSeqID();
        else {
            globalCallback({ type: "stop_listen", error: "Connection refused: Server unavailable" }, null);
        }
    });
    mqttClient.on('connect', function() {
        topics.forEach(topicsub => mqttClient.subscribe(topicsub));
        var topic;
        var queue = {
            sync_api_version: 10,
            max_deltas_able_to_process: 1000,
            delta_batch_size: 500,
            encoding: "JSON",
            entity_fbid: ctx.userID,
        };
        if (ctx.syncToken) {
            topic = "/messenger_sync_get_diffs";
            queue.last_seq_id = ctx.lastSeqId;
            queue.sync_token = ctx.syncToken;
        } else {
            topic = "/messenger_sync_create_queue";
            queue.initial_titan_sequence_id = ctx.lastSeqId;
            queue.device_params = null;
        }
        mqttClient.publish(topic, JSON.stringify(queue), { qos: 1, retain: false });
        mqttClient.publish("/foreground_state", JSON.stringify({"foreground": chatOn}), {qos: 1});
        var rTimeout = setTimeout(function() {
            mqttClient.end();
            getSeqID();
        }, 5000);
        ctx.tmsWait = function() {
            clearTimeout(rTimeout);
            ctx.globalOptions.emitReady ? globalCallback({
                type: "ready",
                error: null
            }) : "";
            delete ctx.tmsWait;
        };
    });
    mqttClient.on('message', function(topic, message, _packet) {
        try {
            var jsonMessage = JSON.parse(message);
        } catch (ex) {
            return log.error("listenMqtt", "SyntaxError: Unexpected token  in JSON at position 0");
        }
        if (topic === "/t_ms") {
            if (ctx.tmsWait && typeof ctx.tmsWait == "function") ctx.tmsWait();
            if (jsonMessage.firstDeltaSeqId && jsonMessage.syncToken) {
                ctx.lastSeqId = jsonMessage.firstDeltaSeqId;
                ctx.syncToken = jsonMessage.syncToken;
            }
            if (jsonMessage.lastIssuedSeqId) ctx.lastSeqId = parseInt(jsonMessage.lastIssuedSeqId);
            for (var i in jsonMessage.deltas) {
                var delta = jsonMessage.deltas[i];
                parseDelta(defaultFuncs, api, ctx, globalCallback, { "delta": delta });
            }
        } else if (topic === "/thread_typing" || topic === "/orca_typing_notifications") {
            var typ = {
                type: "typ",
                isTyping: !!jsonMessage.state,
                from: jsonMessage.sender_fbid.toString(),
                threadID: utils.formatID((jsonMessage.thread || jsonMessage.sender_fbid).toString())
            };
            (function() { globalCallback(null, typ); })();
        } else if (topic === "/orca_presence") {
            if (!ctx.globalOptions.updatePresence) {
                for (var i in jsonMessage.list) {
                    var data = jsonMessage.list[i];
                    var userID = data["u"];
                    var presence = {
                        type: "presence",
                        userID: userID.toString(),
                        timestamp: data["l"] * 1000,
                        statuses: data["p"]
                    };
                    (function() { globalCallback(null, presence); })();
                }
            }
        }
    });
    mqttClient.on('close', function() {
        // (function () { globalCallback("Connection closed."); })();
        // client.end();
    });
}
