      form = {};
    }
    form = form || {};

    callback = callback || function (err, data) {
      if (err) return rejectFunc(err);
      resolveFunc(data);
    };

    if (notAPI) {
      utils
        .get(url, ctx.jar, form, ctx.globalOptions)
        .then(resData => callback(null, resData.body.toString()))
        .catch(function (err) {
          log.error("httpGet", err);
          return callback(err);
        });
    }
    else {
      defaultFuncs
        .get(url, ctx.jar, form)
        .then(resData => callback(null, resData.body.toString()))
        .catch(function (err) {
          log.error("httpGet", err);
          return callback(err);
        });
